<?php
declare(strict_types=1);if(PHP_SAPI!=='cli'){http_response_code(404);exit;}require_once dirname(__DIR__,2).'/includes/account_deletion.php';$aplicar=array_key_exists('apply',getopt('',['apply']));$pdo=obtenerConexion();$ids=$pdo->query("SELECT d.id FROM user_deletions d JOIN usuarios u ON u.id=d.user_id WHERE d.status='periodo_gracia' AND d.effective_at<=NOW() AND u.retention_hold=0 AND u.under_investigation=0 ORDER BY d.id")->fetchAll(PDO::FETCH_COLUMN);$reporte=['modo'=>$aplicar?'aplicar':'simulacion','candidatas'=>count($ids),'anonimizadas'=>0,'errores'=>0];foreach($ids as$id){if(!$aplicar)continue;try{if(anonimizarCuentaVencidaAtenea($pdo,(int)$id))$reporte['anonimizadas']++;}catch(Throwable$e){$reporte['errores']++;error_log('Anonimización cuenta #'.(int)$id.': '.$e->getMessage());}}echo json_encode($reporte,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES).PHP_EOL;
